module top_module(
    input wire clk,
    input wire reset,
    output wire [3:0] count
);reg [3:0] obf_count_reg;

always @(posedge clk) begin
    if (reset) begin
        obf_count_reg <= 4'b0;
    end else begin
        obf_count_reg <= obf_count_reg + 1;
    end
end

assign count = obf_count_reg;

endmodule
